import React, { useState } from 'react';
import { RefreshCw, ArrowRight, CheckCircle, AlertCircle } from 'lucide-react';
import { Dataset, DataTransformation } from '../types';

interface DataTransformationProps {
  dataset: Dataset;
  onTransformation: (transformation: DataTransformation) => void;
}

const DataTransformationComponent: React.FC<DataTransformationProps> = ({ 
  dataset, 
  onTransformation 
}) => {
  const [selectedColumns, setSelectedColumns] = useState<string[]>([]);
  const [transformationType, setTransformationType] = useState<string>('');
  const [parameters, setParameters] = useState<Record<string, any>>({});
  const [previewData, setPreviewData] = useState<any[]>([]);
  const [showPreview, setShowPreview] = useState(false);

  // Get numeric columns for transformations
  const numericColumns = dataset.columns
    .filter(col => col.type === 'number')
    .map(col => col.name);

  const categoricalColumns = dataset.columns
    .filter(col => col.type === 'string' || col.type === 'boolean')
    .map(col => col.name);

  // Apply transformation
  const applyTransformation = () => {
    if (!transformationType || selectedColumns.length === 0) return;

    let transformedData = [...dataset.rows];
    const transformationParams: Record<string, any> = { ...parameters };

    switch (transformationType) {
      case 'normalize':
        // Min-Max normalization
        selectedColumns.forEach(col => {
          const values = transformedData.map(row => row[col]).filter(v => typeof v === 'number' && !isNaN(v));
          if (values.length > 0) {
            const min = Math.min(...values);
            const max = Math.max(...values);
            const range = max - min;
            
            if (range > 0) {
              transformedData = transformedData.map(row => ({
                ...row,
                [col]: range > 0 ? (row[col] - min) / range : row[col]
              }));
            }
          }
        });
        transformationParams.method = 'min-max';
        transformationParams.range = [0, 1];
        break;

      case 'standardize':
        // Z-score standardization
        selectedColumns.forEach(col => {
          const values = transformedData.map(row => row[col]).filter(v => typeof v === 'number' && !isNaN(v));
          if (values.length > 0) {
            const mean = values.reduce((sum, val) => sum + val, 0) / values.length;
            const variance = values.reduce((sum, val) => sum + Math.pow(val - mean, 2), 0) / values.length;
            const std = Math.sqrt(variance);
            
            if (std > 0) {
              transformedData = transformedData.map(row => ({
                ...row,
                [col]: (row[col] - mean) / std
              }));
            }
          }
        });
        transformationParams.method = 'z-score';
        transformationParams.mean = 0;
        transformationParams.std = 1;
        break;

      case 'log':
        // Logarithmic transformation
        selectedColumns.forEach(col => {
          transformedData = transformedData.map(row => ({
            ...row,
            [col]: typeof row[col] === 'number' && row[col] > 0 ? Math.log(row[col]) : row[col]
          }));
        });
        transformationParams.method = 'natural-log';
        break;

      case 'sqrt':
        // Square root transformation
        selectedColumns.forEach(col => {
          transformedData = transformedData.map(row => ({
            ...row,
            [col]: typeof row[col] === 'number' && row[col] >= 0 ? Math.sqrt(row[col]) : row[col]
          }));
        });
        transformationParams.method = 'square-root';
        break;

      case 'bin':
        // Binning/Discretization
        const numBins = parameters.numBins || 5;
        selectedColumns.forEach(col => {
          const values = transformedData.map(row => row[col]).filter(v => typeof v === 'number' && !isNaN(v));
          if (values.length > 0) {
            const min = Math.min(...values);
            const max = Math.max(...values);
            const binWidth = (max - min) / numBins;
            
            transformedData = transformedData.map(row => {
              if (typeof row[col] === 'number' && !isNaN(row[col])) {
                const binIndex = Math.min(Math.floor((row[col] - min) / binWidth), numBins - 1);
                return {
                  ...row,
                  [col]: `Bin ${binIndex + 1} (${(min + binIndex * binWidth).toFixed(2)}-${(min + (binIndex + 1) * binWidth).toFixed(2)})`
                };
              }
              return row;
            });
          }
        });
        transformationParams.method = 'equal-width';
        transformationParams.numBins = numBins;
        break;

      case 'encode':
        // One-hot encoding for categorical variables
        selectedColumns.forEach(col => {
          const uniqueValues = [...new Set(transformedData.map(row => row[col]).filter(v => v !== null && v !== undefined))];
          
          // Create new columns for each unique value
          uniqueValues.forEach(value => {
            const newColName = `${col}_${String(value).replace(/[^a-zA-Z0-9]/g, '_')}`;
            transformedData = transformedData.map(row => ({
              ...row,
              [newColName]: row[col] === value ? 1 : 0
            }));
          });
          
          // Remove original column
          transformedData = transformedData.map(row => {
            const newRow = { ...row };
            delete newRow[col];
            return newRow;
          });
        });
        transformationParams.method = 'one-hot';
        break;
    }

    const transformation: DataTransformation = {
      id: `transform-${Date.now()}`,
      type: transformationType as any,
      columns: selectedColumns,
      method: transformationParams.method || transformationType,
      parameters: transformationParams,
      originalData: dataset.rows,
      transformedData,
    };

    onTransformation(transformation);
    setPreviewData(transformedData.slice(0, 10)); // Show first 10 rows
    setShowPreview(true);
  };

  // Preview transformation
  const previewTransformation = () => {
    applyTransformation();
  };

  // Reset transformation
  const resetTransformation = () => {
    setSelectedColumns([]);
    setTransformationType('');
    setParameters({});
    setPreviewData([]);
    setShowPreview(false);
  };

  const transformationOptions = [
    {
      id: 'normalize',
      name: 'Normalize (Min-Max)',
      description: 'Scale values to range [0, 1]',
      applicableTo: 'numeric',
      icon: '­ƒôè'
    },
    {
      id: 'standardize',
      name: 'Standardize (Z-Score)',
      description: 'Scale values to mean=0, std=1',
      applicableTo: 'numeric',
      icon: '­ƒôê'
    },
    {
      id: 'log',
      name: 'Log Transform',
      description: 'Apply natural logarithm',
      applicableTo: 'numeric',
      icon: '­ƒôë'
    },
    {
      id: 'sqrt',
      name: 'Square Root',
      description: 'Apply square root transformation',
      applicableTo: 'numeric',
      icon: 'ÔêÜ'
    },
    {
      id: 'bin',
      name: 'Binning',
      description: 'Convert continuous to categorical',
      applicableTo: 'numeric',
      icon: '­ƒôª'
    },
    {
      id: 'encode',
      name: 'One-Hot Encode',
      description: 'Convert categorical to binary',
      applicableTo: 'categorical',
      icon: '­ƒöó'
    }
  ];

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-2xl font-bold text-gray-800">Data Transformation</h2>
        <p className="text-gray-600">
          Transform your data for better analysis and modeling
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Transformation Controls */}
        <div>
          <div className="bg-white rounded-lg shadow">
            <div className="px-6 py-4 border-b border-gray-200">
              <h3 className="text-lg font-medium text-gray-800">Transformation Options</h3>
            </div>
            
            <div className="p-6 space-y-4">
              {/* Transformation Type */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Transformation Type
                </label>
                <div className="space-y-2">
                  {transformationOptions.map(option => (
                    <button
                      key={option.id}
                      onClick={() => setTransformationType(option.id)}
                      className={`w-full text-left p-3 rounded-lg border transition-colors ${
                        transformationType === option.id
                          ? 'border-blue-500 bg-blue-50'
                          : 'border-gray-200 hover:border-gray-300'
                      }`}
                    >
                      <div className="flex items-center space-x-3">
                        <span className="text-lg">{option.icon}</span>
                        <div>
                          <div className="font-medium text-gray-800">{option.name}</div>
                          <div className="text-sm text-gray-600">{option.description}</div>
                          <div className="text-xs text-gray-500">
                            For: {option.applicableTo === 'numeric' ? 'Numeric columns' : 'Categorical columns'}
                          </div>
                        </div>
                      </div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Column Selection */}
              {transformationType && (
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Select Columns
                  </label>
                  <div className="space-y-2 max-h-40 overflow-y-auto">
                    {(transformationType === 'encode' ? categoricalColumns : numericColumns).map(column => (
                      <label key={column} className="flex items-center space-x-2">
                        <input
                          type="checkbox"
                          checked={selectedColumns.includes(column)}
                          onChange={(e) => {
                            if (e.target.checked) {
                              setSelectedColumns(prev => [...prev, column]);
                            } else {
                              setSelectedColumns(prev => prev.filter(col => col !== column));
                            }
                          }}
                          className="rounded text-blue-600 focus:ring-blue-500 h-4 w-4"
                        />
                        <span className="text-sm text-gray-700">{column}</span>
                      </label>
                    ))}
                  </div>
                </div>
              )}

              {/* Parameters */}
              {transformationType === 'bin' && (
                <div>
                  <label htmlFor="num-bins" className="block text-sm font-medium text-gray-700 mb-1">
                    Number of Bins
                  </label>
                  <input
                    id="num-bins"
                    type="number"
                    min="2"
                    max="20"
                    value={parameters.numBins || 5}
                    onChange={(e) => setParameters(prev => ({ ...prev, numBins: parseInt(e.target.value) || 5 }))}
                    className="block w-full border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500"
                  />
                </div>
              )}

              {/* Action Buttons */}
              <div className="flex space-x-3 pt-4">
                <button
                  onClick={previewTransformation}
                  disabled={!transformationType || selectedColumns.length === 0}
                  className={`flex-1 flex items-center justify-center py-2 px-4 rounded-md font-medium ${
                    !transformationType || selectedColumns.length === 0
                      ? 'bg-gray-300 text-gray-500 cursor-not-allowed'
                      : 'bg-blue-600 hover:bg-blue-700 text-white'
                  }`}
                >
                  <RefreshCw size={16} className="mr-2" />
                  Preview
                </button>
                
                <button
                  onClick={resetTransformation}
                  className="px-4 py-2 text-gray-700 bg-gray-200 rounded-md hover:bg-gray-300"
                >
                  Reset
                </button>
              </div>
            </div>
          </div>

          {/* Transformation Info */}
          {transformationType && (
            <div className="mt-6 bg-white rounded-lg shadow p-6">
              <h3 className="text-lg font-medium text-gray-800 mb-4">Transformation Details</h3>
              {transformationOptions.find(opt => opt.id === transformationType) && (
                <div className="space-y-3">
                  <div className="flex items-start space-x-3">
                    <span className="text-2xl">
                      {transformationOptions.find(opt => opt.id === transformationType)?.icon}
                    </span>
                    <div>
                      <h4 className="font-medium text-gray-800">
                        {transformationOptions.find(opt => opt.id === transformationType)?.name}
                      </h4>
                      <p className="text-sm text-gray-600 mt-1">
                        {transformationOptions.find(opt => opt.id === transformationType)?.description}
                      </p>
                    </div>
                  </div>
                  
                  <div className="bg-blue-50 rounded-lg p-4 text-sm">
                    <h4 className="font-medium text-blue-800 mb-2">When to Use</h4>
                    <ul className="text-blue-700 space-y-1">
                      {transformationType === 'normalize' && (
                        <>
                          <li>ÔÇó When you need values between 0 and 1</li>
                          <li>ÔÇó For neural networks and some ML algorithms</li>
                          <li>ÔÇó When preserving the original distribution shape</li>
                        </>
                      )}
                      {transformationType === 'standardize' && (
                        <>
                          <li>ÔÇó When data has different scales</li>
                          <li>ÔÇó For algorithms sensitive to scale (SVM, KNN)</li>
                          <li>ÔÇó When you want mean=0 and std=1</li>
                        </>
                      )}
                      {transformationType === 'log' && (
                        <>
                          <li>ÔÇó For right-skewed data</li>
                          <li>ÔÇó To reduce the impact of outliers</li>
                          <li>ÔÇó When dealing with exponential relationships</li>
                        </>
                      )}
                      {transformationType === 'sqrt' && (
                        <>
                          <li>ÔÇó For count data</li>
                          <li>ÔÇó Moderate right-skewed distributions</li>
                          <li>ÔÇó When log transform is too strong</li>
                        </>
                      )}
                      {transformationType === 'bin' && (
                        <>
                          <li>ÔÇó To convert continuous to categorical</li>
                          <li>ÔÇó For decision trees and some algorithms</li>
                          <li>ÔÇó To reduce noise in the data</li>
                        </>
                      )}
                      {transformationType === 'encode' && (
                        <>
                          <li>ÔÇó For machine learning algorithms</li>
                          <li>ÔÇó When categories have no ordinal relationship</li>
                          <li>ÔÇó To avoid ordinal encoding bias</li>
                        </>
                      )}
                    </ul>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Preview Results */}
        <div className="lg:col-span-2">
          <div className="bg-white rounded-lg shadow">
            <div className="px-6 py-4 border-b border-gray-200">
              <h3 className="text-lg font-medium text-gray-800">Transformation Preview</h3>
              <p className="text-sm text-gray-500">
                {showPreview ? 'Preview of transformed data' : 'Select transformation options to see preview'}
              </p>
            </div>
            
            <div className="p-6">
              {showPreview && previewData.length > 0 ? (
                <div className="space-y-4">
                  {/* Transformation Summary */}
                  <div className="bg-green-50 rounded-lg p-4">
                    <div className="flex items-center space-x-2 mb-2">
                      <CheckCircle size={20} className="text-green-600" />
                      <h4 className="font-medium text-green-800">Transformation Applied</h4>
                    </div>
                    <div className="text-sm text-green-700">
                      <p><strong>Type:</strong> {transformationOptions.find(opt => opt.id === transformationType)?.name}</p>
                      <p><strong>Columns:</strong> {selectedColumns.join(', ')}</p>
                      <p><strong>Rows:</strong> {dataset.rows.length}</p>
                    </div>
                  </div>

                  {/* Data Preview */}
                  <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                      <thead className="bg-gray-50">
                        <tr>
                          {Object.keys(previewData[0]).map(column => (
                            <th
                              key={column}
                              className="px-3 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider"
                            >
                              {column}
                            </th>
                          ))}
                        </tr>
                      </thead>
                      <tbody className="bg-white divide-y divide-gray-200">
                        {previewData.map((row, index) => (
                          <tr key={index}>
                            {Object.values(row).map((value, colIndex) => (
                              <td key={colIndex} className="px-3 py-2 text-sm text-gray-900">
                                {typeof value === 'number' ? value.toFixed(4) : String(value)}
                              </td>
                            ))}
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>

                  {/* Apply Button */}
                  <div className="flex justify-end">
                    <button
                      onClick={applyTransformation}
                      className="flex items-center px-4 py-2 bg-green-600 text-white rounded-md hover:bg-green-700"
                    >
                      <ArrowRight size={16} className="mr-2" />
                      Apply Transformation
                    </button>
                  </div>
                </div>
              ) : (
                <div className="text-center py-12">
                  <div className="text-gray-400 mb-4">
                    <RefreshCw size={48} className="mx-auto" />
                  </div>
                  <h3 className="text-lg font-medium text-gray-800 mb-2">No Preview Available</h3>
                  <p className="text-gray-500 max-w-md mx-auto">
                    Select a transformation type and columns, then click "Preview" to see how your data will be transformed.
                  </p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DataTransformationComponent;

import React, { useState, useMemo } from 'react';
import { ArrowDown, ArrowUp, Search, Plus, Trash2, Edit3, Save, X } from 'lucide-react';

interface EditableDataTableProps {
  data: any[];
  columns: string[];
  onDataChange: (newData: any[], newColumns: string[]) => void;
  onRowClick?: (row: any) => void;
  highlightColumn?: string;
}

const EditableDataTable: React.FC<EditableDataTableProps> = ({ 
  data, 
  columns, 
  onDataChange,
  onRowClick,
  highlightColumn
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<{
    key: string;
    direction: 'asc' | 'desc';
  } | null>(null);
  const [currentPage, setCurrentPage] = useState(1);
  const [editingCell, setEditingCell] = useState<{rowIndex: number, column: string} | null>(null);
  const [editingValue, setEditingValue] = useState('');
  const [showAddRow, setShowAddRow] = useState(false);
  const [showAddColumn, setShowAddColumn] = useState(false);
  const [newColumnName, setNewColumnName] = useState('');
  const [deletingRow, setDeletingRow] = useState<number | null>(null);
  const [deletingColumn, setDeletingColumn] = useState<string | null>(null);
  
  const rowsPerPage = 10;

  // Sort the data
  const sortedData = useMemo(() => {
    let sortableData = [...data];
    if (sortConfig !== null) {
      sortableData.sort((a, b) => {
        const valueA = a[sortConfig.key];
        const valueB = b[sortConfig.key];
        
        if (valueA === null || valueA === undefined) return 1;
        if (valueB === null || valueB === undefined) return -1;
        
        // Handle different data types
        if (typeof valueA === 'string' && typeof valueB === 'string') {
          return sortConfig.direction === 'asc' 
            ? valueA.localeCompare(valueB) 
            : valueB.localeCompare(valueA);
        }
        
        return sortConfig.direction === 'asc' 
          ? (valueA > valueB ? 1 : -1) 
          : (valueA < valueB ? 1 : -1);
      });
    }
    return sortableData;
  }, [data, sortConfig]);
  
  // Filter the data based on search term
  const filteredData = useMemo(() => {
    if (!searchTerm.trim()) return sortedData;
    
    return sortedData.filter(row => 
      Object.values(row).some(value => 
        String(value).toLowerCase().includes(searchTerm.toLowerCase())
      )
    );
  }, [sortedData, searchTerm]);
  
  // Calculate pagination
  const totalPages = Math.ceil(filteredData.length / rowsPerPage);
  const paginatedData = filteredData.slice(
    (currentPage - 1) * rowsPerPage,
    currentPage * rowsPerPage
  );
  
  // Handle sort
  const requestSort = (key: string) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  // Get sort indicator
  const getSortIcon = (column: string) => {
    if (!sortConfig || sortConfig.key !== column) {
      return null;
    }
    return sortConfig.direction === 'asc' ? <ArrowUp size={16} /> : <ArrowDown size={16} />;
  };

  // Format cell value for display
  const formatCellValue = (value: any) => {
    if (value === null || value === undefined) {
      return <span className="text-gray-400 italic">NULL</span>;
    }
    
    if (typeof value === 'object') {
      if (value instanceof Date) {
        return value.toLocaleString();
      }
      try {
        return JSON.stringify(value);
      } catch (e) {
        return String(value);
      }
    }
    
    return String(value);
  };

  // Handle cell editing
  const startEditing = (rowIndex: number, column: string, value: any) => {
    setEditingCell({ rowIndex, column });
    setEditingValue(String(value || ''));
  };

  const saveEdit = () => {
    if (!editingCell) return;
    
    const { rowIndex, column } = editingCell;
    const newData = [...data];
    
    // Find the actual row index in the original data
    const actualRowIndex = data.findIndex(row => 
      JSON.stringify(row) === JSON.stringify(paginatedData[rowIndex])
    );
    
    if (actualRowIndex !== -1) {
      newData[actualRowIndex] = { ...newData[actualRowIndex], [column]: editingValue };
      onDataChange(newData, columns);
    }
    
    setEditingCell(null);
    setEditingValue('');
  };

  const cancelEdit = () => {
    setEditingCell(null);
    setEditingValue('');
  };

  // Handle key press in edit mode
  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      saveEdit();
    } else if (e.key === 'Escape') {
      cancelEdit();
    }
  };

  // Add new row
  const addRow = () => {
    const newRow: any = {};
    columns.forEach(col => {
      newRow[col] = '';
    });
    
    const newData = [...data, newRow];
    onDataChange(newData, columns);
    setShowAddRow(false);
  };

  // Delete row
  const deleteRow = (rowIndex: number) => {
    const newData = data.filter((_, index) => index !== rowIndex);
    onDataChange(newData, columns);
    setDeletingRow(null);
  };

  // Add new column
  const addColumn = () => {
    if (!newColumnName.trim()) return;
    
    const newColumns = [...columns, newColumnName.trim()];
    const newData = data.map(row => ({
      ...row,
      [newColumnName.trim()]: ''
    }));
    
    onDataChange(newData, newColumns);
    setNewColumnName('');
    setShowAddColumn(false);
  };

  // Delete column
  const deleteColumn = (columnName: string) => {
    const newColumns = columns.filter(col => col !== columnName);
    const newData = data.map(row => {
      const newRow = { ...row };
      delete newRow[columnName];
      return newRow;
    });
    
    onDataChange(newData, newColumns);
    setDeletingColumn(null);
  };

  return (
    <div className="overflow-hidden rounded-lg border border-gray-200 shadow">
      {/* Table Controls */}
      <div className="bg-white p-4 border-b border-gray-200 flex flex-wrap items-center justify-between">
        <div className="flex items-center space-x-4">
          <div className="relative">
            <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
              <Search size={18} className="text-gray-500" />
            </div>
            <input
              type="text"
              className="pl-10 pr-4 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
              placeholder="Search data..."
              value={searchTerm}
              onChange={(e) => {
                setSearchTerm(e.target.value);
                setCurrentPage(1);
              }}
            />
          </div>
          
          <button
            onClick={() => setShowAddRow(true)}
            className="flex items-center px-3 py-2 bg-green-600 text-white rounded-md hover:bg-green-700"
          >
            <Plus size={16} className="mr-1" />
            Add Row
          </button>
          
          <button
            onClick={() => setShowAddColumn(true)}
            className="flex items-center px-3 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700"
          >
            <Plus size={16} className="mr-1" />
            Add Column
          </button>
        </div>
        
        <div className="flex items-center space-x-2 mt-2 sm:mt-0">
          <span className="text-sm text-gray-700">
            {filteredData.length} results
          </span>
        </div>
      </div>
      
      {/* Add Row Form */}
      {showAddRow && (
        <div className="bg-blue-50 p-4 border-b border-blue-200">
          <div className="flex items-center space-x-4">
            <span className="text-sm font-medium text-blue-800">Add New Row:</span>
            {columns.map(column => (
              <div key={column} className="flex-1">
                <input
                  type="text"
                  placeholder={column}
                  className="w-full px-3 py-1 border border-blue-300 rounded text-sm"
                  onKeyPress={(e) => {
                    if (e.key === 'Enter') addRow();
                    if (e.key === 'Escape') setShowAddRow(false);
                  }}
                />
              </div>
            ))}
            <button
              onClick={addRow}
              className="px-3 py-1 bg-green-600 text-white rounded text-sm hover:bg-green-700"
            >
              <Save size={14} />
            </button>
            <button
              onClick={() => setShowAddRow(false)}
              className="px-3 py-1 bg-gray-500 text-white rounded text-sm hover:bg-gray-600"
            >
              <X size={14} />
            </button>
          </div>
        </div>
      )}
      
      {/* Add Column Form */}
      {showAddColumn && (
        <div className="bg-blue-50 p-4 border-b border-blue-200">
          <div className="flex items-center space-x-4">
            <span className="text-sm font-medium text-blue-800">Add New Column:</span>
            <input
              type="text"
              placeholder="Column name"
              value={newColumnName}
              onChange={(e) => setNewColumnName(e.target.value)}
              className="flex-1 px-3 py-1 border border-blue-300 rounded text-sm"
              onKeyPress={(e) => {
                if (e.key === 'Enter') addColumn();
                if (e.key === 'Escape') setShowAddColumn(false);
              }}
            />
            <button
              onClick={addColumn}
              className="px-3 py-1 bg-green-600 text-white rounded text-sm hover:bg-green-700"
            >
              <Save size={14} />
            </button>
            <button
              onClick={() => setShowAddColumn(false)}
              className="px-3 py-1 bg-gray-500 text-white rounded text-sm hover:bg-gray-600"
            >
              <X size={14} />
            </button>
          </div>
        </div>
      )}
      
      {/* Table */}
      <div className="overflow-x-auto">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-2 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Actions
              </th>
              {columns.map((column) => (
                <th
                  key={column}
                  className="px-6 py-3 text-left text-xs font-medium uppercase tracking-wider cursor-pointer select-none hover:bg-gray-100"
                >
                  <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-1" onClick={() => requestSort(column)}>
                      <span>{column}</span>
                      {getSortIcon(column)}
                    </div>
                    <button
                      onClick={() => setDeletingColumn(column)}
                      className="text-red-500 hover:text-red-700 opacity-0 hover:opacity-100 transition-opacity"
                      title="Delete column"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {paginatedData.length > 0 ? (
              paginatedData.map((row, rowIndex) => (
                <tr 
                  key={rowIndex} 
                  onClick={() => onRowClick && onRowClick(row)}
                  className={onRowClick ? "hover:bg-gray-50 cursor-pointer" : ""}
                >
                  <td className="px-2 py-4 whitespace-nowrap text-sm">
                    <button
                      onClick={() => setDeletingRow((currentPage - 1) * rowsPerPage + rowIndex)}
                      className="text-red-500 hover:text-red-700"
                      title="Delete row"
                    >
                      <Trash2 size={14} />
                    </button>
                  </td>
                  {columns.map((column) => (
                    <td 
                      key={`${rowIndex}-${column}`} 
                      className={`px-6 py-4 whitespace-nowrap text-sm ${
                        highlightColumn === column ? 'bg-blue-50' : ''
                      }`}
                    >
                      {editingCell?.rowIndex === rowIndex && editingCell?.column === column ? (
                        <div className="flex items-center space-x-2">
                          <input
                            type="text"
                            value={editingValue}
                            onChange={(e) => setEditingValue(e.target.value)}
                            onKeyPress={handleKeyPress}
                            onBlur={saveEdit}
                            className="flex-1 px-2 py-1 border border-blue-300 rounded text-sm focus:ring-blue-500 focus:border-blue-500"
                            autoFocus
                          />
                          <button
                            onClick={saveEdit}
                            className="text-green-600 hover:text-green-800"
                          >
                            <Save size={14} />
                          </button>
                          <button
                            onClick={cancelEdit}
                            className="text-gray-500 hover:text-gray-700"
                          >
                            <X size={14} />
                          </button>
                        </div>
                      ) : (
                        <div 
                          className="flex items-center justify-between group"
                          onDoubleClick={() => startEditing(rowIndex, column, row[column])}
                        >
                          <span>{formatCellValue(row[column])}</span>
                          <button
                            onClick={() => startEditing(rowIndex, column, row[column])}
                            className="text-gray-400 hover:text-gray-600 opacity-0 group-hover:opacity-100 transition-opacity"
                            title="Edit cell"
                          >
                            <Edit3 size={14} />
                          </button>
                        </div>
                      )}
                    </td>
                  ))}
                </tr>
              ))
            ) : (
              <tr>
                <td 
                  colSpan={columns.length + 1} 
                  className="px-6 py-4 text-center text-sm text-gray-500"
                >
                  No data found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
      
      {/* Pagination Controls */}
      {totalPages > 1 && (
        <div className="bg-white px-4 py-3 flex items-center justify-between border-t border-gray-200">
          <div>
            <p className="text-sm text-gray-700">
              Showing <span className="font-medium">{(currentPage - 1) * rowsPerPage + 1}</span> to{' '}
              <span className="font-medium">
                {Math.min(currentPage * rowsPerPage, filteredData.length)}
              </span>{' '}
              of <span className="font-medium">{filteredData.length}</span> results
            </p>
          </div>
          <div>
            <nav className="flex items-center">
              <button
                onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                disabled={currentPage === 1}
                className={`relative inline-flex items-center px-4 py-2 text-sm font-medium rounded-md ${
                  currentPage === 1
                    ? 'text-gray-300 cursor-not-allowed'
                    : 'text-gray-700 hover:bg-gray-50'
                }`}
              >
                Previous
              </button>
              <span className="mx-2">
                Page {currentPage} of {totalPages}
              </span>
              <button
                onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                disabled={currentPage === totalPages}
                className={`relative inline-flex items-center px-4 py-2 text-sm font-medium rounded-md ${
                  currentPage === totalPages
                    ? 'text-gray-300 cursor-not-allowed'
                    : 'text-gray-700 hover:bg-gray-50'
                }`}
              >
                Next
              </button>
            </nav>
          </div>
        </div>
      )}
      
      {/* Delete Confirmation Modals */}
      {deletingRow !== null && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 max-w-sm w-full mx-4">
            <h3 className="text-lg font-medium text-gray-900 mb-4">Delete Row</h3>
            <p className="text-gray-600 mb-6">Are you sure you want to delete this row? This action cannot be undone.</p>
            <div className="flex space-x-3">
              <button
                onClick={() => deleteRow(deletingRow)}
                className="flex-1 bg-red-600 text-white px-4 py-2 rounded-md hover:bg-red-700"
              >
                Delete
              </button>
              <button
                onClick={() => setDeletingRow(null)}
                className="flex-1 bg-gray-300 text-gray-700 px-4 py-2 rounded-md hover:bg-gray-400"
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
      
      {deletingColumn !== null && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 max-w-sm w-full mx-4">
            <h3 className="text-lg font-medium text-gray-900 mb-4">Delete Column</h3>
            <p className="text-gray-600 mb-6">
              Are you sure you want to delete the column "{deletingColumn}"? This action cannot be undone.
            </p>
            <div className="flex space-x-3">
              <button
                onClick={() => deleteColumn(deletingColumn)}
                className="flex-1 bg-red-600 text-white px-4 py-2 rounded-md hover:bg-red-700"
              >
                Delete
              </button>
              <button
                onClick={() => setDeletingColumn(null)}
                className="flex-1 bg-gray-300 text-gray-700 px-4 py-2 rounded-md hover:bg-gray-400"
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default EditableDataTable;

import React, { useState } from 'react';
import { useDropzone } from 'react-dropzone';
import { Upload, AlertCircle, CheckCircle, X } from 'lucide-react';
import { loadProjectFromFile } from '../utils/exporters';
import { validateDIPProject } from '../utils/dipSchema';
import { useProject } from '../context/ProjectContext';
import { useToast } from '../context/ToastContext';
import { DIPProject } from '../types';

interface LoadProjectDropzoneProps {
  onClose: () => void;
}

const LoadProjectDropzone: React.FC<LoadProjectDropzoneProps> = ({ onClose }) => {
  const { dispatch } = useProject();
  const { showToast } = useToast();
  const [preview, setPreview] = useState<DIPProject | null>(null);
  const [fileError, setFileError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const onDrop = async (acceptedFiles: File[]) => {
    const file = acceptedFiles[0];
    if (!file) return;

    setFileError(null);
    setPreview(null);
    setIsLoading(true);

    try {
      const raw = await loadProjectFromFile(file);
      const validation = validateDIPProject(raw);

      if (!validation.success) {
        setFileError(validation.error || 'Invalid .dip file.');
        showToast(validation.error || 'Invalid .dip file.', 'error');
        return;
      }

      setPreview(raw as DIPProject);
    } catch (err: any) {
      const msg = err?.message || 'Failed to parse project file.';
      setFileError(msg);
      showToast(msg, 'error');
    } finally {
      setIsLoading(false);
    }
  };

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: { 'application/json': ['.dip'] },
    maxFiles: 1,
  });

  const handleConfirmLoad = () => {
    if (!preview) return;
    dispatch({ type: 'LOAD_PROJECT', payload: preview });
    showToast(`Project "${preview.projectName}" restored successfully!`, 'success');
    onClose();
  };

  return (
    <div
      style={{
        position: 'fixed',
        inset: 0,
        background: 'rgba(0,0,0,0.55)',
        zIndex: 1000,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 16,
      }}
    >
      <div
        style={{
          background: '#fff',
          borderRadius: 16,
          maxWidth: 480,
          width: '100%',
          padding: 28,
          boxShadow: '0 20px 60px rgba(0,0,0,0.2)',
        }}
      >
        {/* Header */}
        <div className="flex items-center justify-between mb-5">
          <h2 className="text-xl font-bold text-gray-800">Load Project</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors">
            <X size={22} />
          </button>
        </div>

        {!preview ? (
          <>
            {/* Drop zone */}
            <div
              {...getRootProps()}
              className={`border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-colors ${
                isDragActive
                  ? 'border-blue-500 bg-blue-50'
                  : 'border-gray-300 bg-gray-50 hover:border-blue-400 hover:bg-blue-50'
              }`}
            >
              <input {...getInputProps()} />
              {isLoading ? (
                <div className="flex flex-col items-center gap-2">
                  <svg className="animate-spin h-10 w-10 text-blue-500" viewBox="0 0 24 24" fill="none">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                  </svg>
                  <p className="text-blue-600 font-medium">Reading project fileÔÇª</p>
                </div>
              ) : (
                <>
                  <Upload size={40} className="text-blue-400 mx-auto mb-3" />
                  <p className="text-gray-700 font-medium">Drop your .dip file here</p>
                  <p className="text-gray-500 text-sm mt-1">or click to browse</p>
                  <p className="text-xs text-gray-400 mt-3">Only .dip (DataInsight Project) files are accepted</p>
                </>
              )}
            </div>

            {/* Error */}
            {fileError && (
              <div className="mt-4 flex items-start gap-2 p-3 bg-red-50 border border-red-200 rounded-lg">
                <AlertCircle size={18} className="text-red-500 flex-shrink-0 mt-0.5" />
                <p className="text-sm text-red-700">{fileError}</p>
              </div>
            )}
          </>
        ) : (
          <>
            {/* Preview */}
            <div className="mb-5 p-4 bg-green-50 border border-green-200 rounded-xl">
              <div className="flex items-center gap-2 mb-3">
                <CheckCircle size={20} className="text-green-600" />
                <span className="font-semibold text-green-800">Valid project file detected</span>
              </div>
              <dl className="grid grid-cols-2 gap-2 text-sm">
                <dt className="text-gray-500">Project Name</dt>
                <dd className="font-medium text-gray-800">{preview.projectName}</dd>
                <dt className="text-gray-500">Created</dt>
                <dd className="font-medium text-gray-800">
                  {new Date(preview.createdAt).toLocaleDateString()}
                </dd>
                <dt className="text-gray-500">Rows</dt>
                <dd className="font-medium text-gray-800">
                  {preview.processedDataset?.rows.length.toLocaleString() ?? 'ÔÇö'}
                </dd>
                <dt className="text-gray-500">Columns</dt>
                <dd className="font-medium text-gray-800">
                  {preview.processedDataset?.columns.length ?? 'ÔÇö'}
                </dd>
                <dt className="text-gray-500">History Steps</dt>
                <dd className="font-medium text-gray-800">{preview.history.length}</dd>
                <dt className="text-gray-500">ML Results</dt>
                <dd className="font-medium text-gray-800">{preview.mlResults.length}</dd>
                <dt className="text-gray-500">Saved Charts</dt>
                <dd className="font-medium text-gray-800">{preview.charts.length}</dd>
              </dl>
            </div>

            <div className="p-3 bg-amber-50 border border-amber-200 rounded-lg mb-4">
              <p className="text-sm text-amber-800">
                ÔÜá Loading this project will <strong>replace your current session</strong>. Make sure you've saved any work first.
              </p>
            </div>

            <div className="flex gap-3">
              <button
                onClick={() => setPreview(null)}
                className="flex-1 py-2.5 px-4 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 transition-colors font-medium"
              >
                Cancel
              </button>
              <button
                onClick={handleConfirmLoad}
                className="flex-1 py-2.5 px-4 bg-blue-600 rounded-lg text-white font-medium hover:bg-blue-700 transition-colors"
              >
                Restore Project
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default LoadProjectDropzone;

import React, { useState } from 'react';
import { ChevronLeft, ChevronRight, Save, FolderOpen, History, Clock, Edit2, Check, Lightbulb, Brain, Database, Plus, Trash2 } from 'lucide-react';
import { useProject } from '../context/ProjectContext';
import { useToast } from '../context/ToastContext';
import { saveProject } from '../utils/exporters';
import LoadProjectDropzone from './LoadProjectDropzone';
import VersionHistory from './VersionHistory';

type Route = {
  id: string;
  name: string;
  icon: React.ReactNode;
  disabled?: boolean;
};

interface SidebarProps {
  isOpen: boolean;
  toggleSidebar: () => void;
  routes: Route[];
  activeTab: string;
  setActiveTab: (tab: string) => void;
  onToggleTimeline: () => void;
  onToggleSuggestions: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({
  isOpen,
  toggleSidebar,
  routes,
  activeTab,
  setActiveTab,
  onToggleTimeline,
  onToggleSuggestions,
}) => {
  const { state, dispatch } = useProject();
  const { showToast } = useToast();

  const [showLoadModal, setShowLoadModal] = useState(false);
  const [showVersions, setShowVersions] = useState(false);
  const [editingName, setEditingName] = useState(false);
  const [nameInput, setNameInput] = useState(state.projectName);

  const handleSaveProject = () => {
    if (Object.keys(state.datasets).length === 0) {
      showToast('No dataset loaded. Upload data first.', 'warning');
      return;
    }
    const label = `v${state.versions.length + 1} ÔÇö ${new Date().toLocaleTimeString()}`;
    dispatch({ type: 'SAVE_VERSION', payload: label });
    saveProject(state);
    showToast(`Project "${state.projectName}" saved as .dip file!`, 'success');
  };

  const handleNameConfirm = () => {
    const trimmed = nameInput.trim() || 'Untitled Project';
    dispatch({ type: 'SET_PROJECT_NAME', payload: trimmed });
    setEditingName(false);
    showToast('Project name updated.', 'info');
  };

  const autoSavedLabel = state.lastAutoSaved
    ? `Auto-saved ${formatRelativeTime(state.lastAutoSaved)}`
    : null;

  return (
    <>
      <div
        className={`bg-white shadow-lg transition-all duration-300 ease-in-out flex flex-col ${
          isOpen ? 'w-64' : 'w-20'
        } relative z-40`}
        style={{ minHeight: '100vh' }}
      >
        {/* Top branding + toggle */}
        <div className="flex items-center justify-between h-16 px-4 border-b border-gray-100 flex-shrink-0">
          {isOpen && (
            <div className="flex flex-col min-w-0">
              <span className="text-base font-bold text-blue-600 truncate">DataInsight Pro</span>
              {editingName ? (
                <div className="flex items-center gap-1 mt-0.5">
                  <input
                    value={nameInput}
                    onChange={(e) => setNameInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleNameConfirm()}
                    className="text-xs border border-blue-300 rounded px-1 py-0.5 w-28 focus:outline-none focus:ring-1 focus:ring-blue-400"
                    autoFocus
                  />
                  <button onClick={handleNameConfirm} className="text-green-600 hover:text-green-700">
                    <Check size={13} />
                  </button>
                </div>
              ) : (
                <div className="flex items-center gap-1 mt-0.5">
                  <span className="text-xs text-gray-500 truncate max-w-[130px]" title={state.projectName}>{state.projectName}</span>
                  <button
                    onClick={() => { setNameInput(state.projectName); setEditingName(true); }}
                    className="text-gray-400 hover:text-gray-600 flex-shrink-0"
                  >
                    <Edit2 size={11} />
                  </button>
                </div>
              )}
            </div>
          )}
          <button
            onClick={toggleSidebar}
            className="p-2 rounded-full hover:bg-gray-100 focus:outline-none focus:ring-2 focus:ring-blue-400 flex-shrink-0"
          >
            {isOpen ? <ChevronLeft size={18} /> : <ChevronRight size={18} />}
          </button>
        </div>

        {/* Project & Panels */}
        <div className="px-3 py-3 border-b border-gray-100 space-y-1.5 flex-shrink-0">
          <div className="grid grid-cols-2 gap-1.5">
            <button
              onClick={handleSaveProject}
              title="Save Project"
              className="flex items-center justify-center gap-2 px-2 py-2 rounded-lg text-xs font-semibold bg-blue-600 text-white hover:bg-blue-700 transition"
            >
              <Save size={14} /> {isOpen && "Save"}
            </button>
            <button
              onClick={() => setShowLoadModal(true)}
              title="Load Project"
              className="flex items-center justify-center gap-2 px-2 py-2 rounded-lg text-xs font-semibold border border-gray-200 text-gray-700 hover:bg-gray-50 transition"
            >
              <FolderOpen size={14} /> {isOpen && "Load"}
            </button>
          </div>

          {/* Panels Grid */}
          <div className="grid grid-cols-3 gap-1.5 mt-2">
             <button onClick={onToggleTimeline} title="Workflow Timeline" className="flex flex-col items-center justify-center p-2 rounded-lg text-xs font-medium border border-gray-200 text-gray-600 hover:bg-blue-50 hover:text-blue-600 hover:border-blue-200 transition">
               <Clock size={16} className="mb-1" />
               {isOpen && <span className="text-[10px] uppercase truncate">Timeline</span>}
             </button>
             <button onClick={() => setShowVersions(true)} title="Dataset Versions" className="flex flex-col items-center justify-center p-2 rounded-lg text-xs font-medium border border-gray-200 text-gray-600 hover:bg-indigo-50 hover:text-indigo-600 hover:border-indigo-200 transition">
               <History size={16} className="mb-1" />
               {isOpen && <span className="text-[10px] uppercase truncate">Versions</span>}
             </button>
             <button onClick={onToggleSuggestions} title="Smart Suggestions" className="flex flex-col items-center justify-center p-2 rounded-lg text-xs font-medium border border-gray-200 text-gray-600 hover:bg-yellow-50 hover:text-yellow-600 hover:border-yellow-200 transition">
               <Lightbulb size={16} className="mb-1" />
               {isOpen && <span className="text-[10px] uppercase truncate">Insights</span>}
             </button>
          </div>
        </div>

        {/* Workspace Datasets (Feature 9) */}
        {isOpen && Object.keys(state.datasets).length > 0 && (
          <div className="px-3 pt-3 pb-1 border-b border-gray-100 flex-shrink-0">
            <p className="text-[10px] uppercase font-bold text-gray-400 mb-1 px-1">Active Dataset</p>
            <select
              value={state.activeDatasetId || ''}
              onChange={(e) => dispatch({ type: 'SET_ACTIVE_DATASET', payload: e.target.value })}
              className="w-full text-xs border border-gray-300 rounded p-1.5 mb-2 focus:ring-1 focus:ring-blue-500 truncate"
            >
              {Object.values(state.datasets).map(ds => (
                <option key={ds.id} value={ds.id}>{ds.name} ({ds.rows.length} rows)</option>
              ))}
            </select>
          </div>
        )}

        {/* Status flags */}
        {(autoSavedLabel || state.isDirty) && isOpen && (
          <div className="px-4 py-2 border-b border-gray-100 flex-shrink-0 flex flex-col gap-1">
            {autoSavedLabel && <div className="flex items-center gap-1.5"><span className="w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse" /><span className="text-[10px] text-gray-400 truncate">{autoSavedLabel}</span></div>}
            {state.isDirty && !state.lastAutoSaved && <div className="flex items-center gap-1.5"><Clock size={10} className="text-amber-400" /><span className="text-[10px] text-amber-500">Unsaved changes</span></div>}
          </div>
        )}

        {/* Nav routes */}
        <nav className="flex-1 overflow-y-auto p-3">
          {isOpen && <p className="text-[10px] uppercase font-bold text-gray-400 mb-2 px-1 mt-1">Tools</p>}
          <ul className="space-y-1">
            {routes.map((route) => (
              <li key={route.id}>
                <button
                  onClick={() => !route.disabled && setActiveTab(route.id)}
                  title={route.name}
                  className={`w-full flex items-center py-2.5 px-3 rounded-lg transition-all duration-150 ${
                    activeTab === route.id
                      ? 'bg-blue-100 text-blue-700 shadow-sm'
                      : route.disabled
                      ? 'text-gray-300 cursor-not-allowed'
                      : 'text-gray-600 hover:bg-gray-100 hover:text-gray-800'
                  }`}
                  disabled={route.disabled}
                >
                  <span className="flex-shrink-0">{route.icon}</span>
                  {isOpen && (
                    <span className="ml-3 font-medium truncate text-sm">{route.name}</span>
                  )}
                </button>
              </li>
            ))}
          </ul>
        </nav>
      </div>

      {showLoadModal && <LoadProjectDropzone onClose={() => setShowLoadModal(false)} />}
      {showVersions && <VersionHistory onClose={() => setShowVersions(false)} />}
    </>
  );
};

function formatRelativeTime(ts: number): string {
  const diffSec = Math.floor((Date.now() - ts) / 1000);
  const diffMin = Math.floor(diffSec / 60);
  if (diffMin >= 1) return `${diffMin}m ago`;
  return `${diffSec}s ago`;
}

