/**
 * Generate a comprehensive PDF report of the project session.
 */
export function generatePDFReport(
  state: ProjectState,
  chartImageBase64?: string | null
): void {
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
  const safeName = (state.projectName || 'Project').replace(/[^a-zA-Z0-9_-]/g, '_');
  const pageW = doc.internal.pageSize.getWidth();
  const margin = 15;

  // ÔöÇÔöÇ Cover / Header ÔöÇÔöÇ
  doc.setFillColor(37, 99, 235);
  doc.rect(0, 0, pageW, 40, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(22);
  doc.setFont('helvetica', 'bold');
  doc.text('DataInsight Pro', margin, 18);
  doc.setFontSize(13);
  doc.setFont('helvetica', 'normal');
  doc.text(`Project Report: ${state.projectName || 'Untitled'}`, margin, 30);

  doc.setTextColor(100, 100, 100);
  doc.setFontSize(9);
  doc.text(`Generated: ${new Date().toLocaleString()}`, margin, 46);

  let y = 55;

  // ÔöÇÔöÇ Dataset Summary ÔöÇÔöÇ
  if (state.processedDataset) {
    const ds = state.processedDataset;
    doc.setTextColor(30, 30, 30);
    doc.setFontSize(13);
    doc.setFont('helvetica', 'bold');
    doc.text('Dataset Summary', margin, y);
    y += 6;

    autoTable(doc, {
      startY: y,
      head: [['Property', 'Value']],
      body: [
        ['File Name', ds.originalFilename],
        ['Format', ds.originalFormat.toUpperCase()],
        ['Total Rows', ds.rows.length.toLocaleString()],
        ['Total Columns', ds.columns.length.toLocaleString()],
        ['Date Modified', new Date(ds.dateModified).toLocaleString()],
      ],
      styles: { fontSize: 9 },
      headStyles: { fillColor: [37, 99, 235] },
      margin: { left: margin, right: margin },
    });
    y = (doc as any).lastAutoTable.finalY + 10;

    // Column details table
    doc.setFontSize(11);
    doc.setFont('helvetica', 'bold');
    doc.text('Column Details', margin, y);
    y += 4;

    const colRows = ds.columns.slice(0, 20).map((col) => [
      col.name,
      col.type,
      col.missing != null ? col.missing.toString() : '0',
      col.mean != null ? col.mean.toFixed(3) : '-',
      col.min != null ? col.min.toString() : '-',
      col.max != null ? col.max.toString() : '-',
    ]);

    autoTable(doc, {
      startY: y,
      head: [['Column', 'Type', 'Missing', 'Mean', 'Min', 'Max']],
      body: colRows,
      styles: { fontSize: 8 },
      headStyles: { fillColor: [37, 99, 235] },
      margin: { left: margin, right: margin },
    });
    y = (doc as any).lastAutoTable.finalY + 10;
  }

  // ÔöÇÔöÇ Workflow History ÔöÇÔöÇ
  if (state.history.length > 0) {
    if (y > 230) { doc.addPage(); y = 20; }
    doc.setFontSize(13);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(30, 30, 30);
    doc.text('Workflow History', margin, y);
    y += 4;

    const histRows = state.history.slice(0, 30).map((h) => [
      h.action,
      h.description,
      new Date(h.timestamp).toLocaleString(),
    ]);

    autoTable(doc, {
      startY: y,
      head: [['Action', 'Description', 'Timestamp']],
      body: histRows,
      styles: { fontSize: 8 },
      headStyles: { fillColor: [79, 70, 229] },
      margin: { left: margin, right: margin },
    });
    y = (doc as any).lastAutoTable.finalY + 10;
  }

  // ÔöÇÔöÇ ML Results ÔöÇÔöÇ
  if (state.mlResults.length > 0) {
    if (y > 230) { doc.addPage(); y = 20; }
    doc.setFontSize(13);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(30, 30, 30);
    doc.text('Machine Learning Results', margin, y);
    y += 4;

    const mlRows = state.mlResults.map((r) => [
      r.type.charAt(0).toUpperCase() + r.type.slice(1),
      r.title,
      r.description,
      r.accuracy != null ? `${(r.accuracy * 100).toFixed(1)}%` : '-',
    ]);

    autoTable(doc, {
      startY: y,
      head: [['Type', 'Title', 'Description', 'Accuracy']],
      body: mlRows,
      styles: { fontSize: 8 },
      headStyles: { fillColor: [16, 185, 129] },
      margin: { left: margin, right: margin },
    });
    y = (doc as any).lastAutoTable.finalY + 10;
  }

  // ÔöÇÔöÇ Chart image ÔöÇÔöÇ
  if (chartImageBase64) {
    if (y > 170) { doc.addPage(); y = 20; }
    doc.setFontSize(13);
    doc.setFont('helvetica', 'bold');
    doc.text('Visualization Snapshot', margin, y);
    y += 5;
    try {
      const imgW = pageW - margin * 2;
      const imgH = imgW * 0.55;
      doc.addImage(chartImageBase64, 'PNG', margin, y, imgW, imgH);
      y += imgH + 10;
    } catch {
      // skip image if it fails
    }
  }

  // ÔöÇÔöÇ Footer on all pages ÔöÇÔöÇ
  const totalPages = (doc.internal as any).getNumberOfPages?.() ?? 1;
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i);
    doc.setFontSize(8);
    doc.setTextColor(180, 180, 180);
    doc.text(
      `DataInsight Pro ÔÇö ${state.projectName} ÔÇö Page ${i} of ${totalPages}`,
      pageW / 2,
      doc.internal.pageSize.getHeight() - 8,
      { align: 'center' }
    );
  }

  doc.save(`${safeName}_report.pdf`);
}

import Papa from 'papaparse';
import * as XLSX from 'xlsx';

/**
 * Parse CSV file into array of objects
 */
export const parseCSV = (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    Papa.parse(file, {
      header: true, // First row is header
      dynamicTyping: true, // Convert numbers and booleans
      skipEmptyLines: true,
      worker: true, // Offload to background web worker to prevent UI freezing
      complete: (results) => {
        if (results.errors.length > 0) {
          reject(new Error(`CSV parsing error: ${results.errors[0].message}`));
        } else {
          resolve(results.data);
        }
      },
      error: (error) => {
        reject(error);
      }
    });
  });
};

/**
 * Parse Excel file into array of objects
 */
export const parseExcel = async (file: File): Promise<any[]> => {
  try {
    const data = await file.arrayBuffer();
    const workbook = XLSX.read(data);

    // Get first sheet
    const firstSheetName = workbook.SheetNames[0];
    const worksheet = workbook.Sheets[firstSheetName];

    // Convert to JSON
    const jsonData = XLSX.utils.sheet_to_json(worksheet, { raw: false });
    return jsonData;
  } catch (error) {
    throw new Error(`Excel parsing error: ${error instanceof Error ? error.message : 'Unknown error'}`);
  }
};

/**
 * Parse JSON file into array of objects
 */
export const parseJSON = async (file: File): Promise<any[]> => {
  try {
    const text = await file.text();
    const data = JSON.parse(text);

    // Check if data is an array
    if (!Array.isArray(data)) {
      throw new Error('JSON file must contain an array of objects');
    }

    return data;
  } catch (error) {
    throw new Error(`JSON parsing error: ${error instanceof Error ? error.message : 'Unknown error'}`);
  }
};
